from pyspark.sql import functions as F

# 1. 创建价格区间 (Bucketizing)
# 将价格向下取整到 10 的倍数，例如 261 -> 260
bucket_df = df_final.withColumn("price_bucket", (F.floor(F.col("price") / 10) * 10))

# 2. 统计各区间的机构强度
institution_strength = bucket_df.filter(F.col("is_sweep") == "SIGNAL: SWEEP") \
    .groupBy("price_bucket") \
    .agg(
        F.sum("vol_5").alias("total_institutional_volume"),
        F.count("*").alias("sweep_frequency")
    ) \
    .orderBy(F.desc("total_institutional_volume"))

institution_strength.show()
